class Solution {
    public int[] maxDepthAfterSplit(String seq) {
        int currentDepth = 0;
        int[] ans = new int[seq.length()];
        for (int i = 0; i < seq.length(); i++) {
            char c = seq.charAt(i);
            if (c == '(') {
                if (currentDepth % 2 == 0) {
                    ans[i] = 0;
                } else {
                    ans[i] = 1;
                }
                currentDepth++;
            } else {
                if (currentDepth % 2 == 0) {
                    ans[i] = 0;
                } else {
                    ans[i] = 1;
                }
                currentDepth--;
            }
        }
        return ans;
    }
}

